INSERT INTO COTDL.TBL_ACCESS_LOG_SOURCE (
    source_id, source_name, source_type, db_name, db_type, hostname, port,
    schema_name, description, collect_interval, table_filter, exclude_accounts, is_active, status, reg_user_id
) VALUES (
    #{sourceId}, #{sourceName}, #{sourceType}, #{dbName}, #{dbType}, #{hostname}, #{port},
    #{schemaName}, #{description}, #{collectInterval}, #{tableFilter}, #{excludeAccounts}, #{isActive}, 'STOPPED', #{regUserId}
)

mapper.select:
SELECT * FROM COTDL.TBL_ACCESS_LOG_SOURCE
AND (source_name LIKE CONCAT('%', #{keyword}, '%') OR db_name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY reg_date DESC LIMIT #{offset}, #{amount}

mapper.update:
UPDATE COTDL.TBL_ACCESS_LOG_SOURCE SET
    status = #{status},
    error_msg = #{errorMsg}
WHERE source_id = #{sourceId}

UPDATE COTDL.TBL_ACCESS_LOG_SOURCE SET
    last_collect_time = #{lastCollectTime},
    total_collected = total_collected + #{collectedCount}
WHERE source_id = #{sourceId}

mapper.insert:
INSERT INTO COTDL.TBL_ACCESS_LOG_COLLECT_STATUS (
    source_id, collect_start, collect_end, last_offset, collected_count, status, error_msg, retry_count
) VALUES (
    #{sourceId}, #{collectStart}, #{collectEnd}, #{lastOffset}, #{collectedCount}, #{status}, #{errorMsg}, #{retryCount}
)

mapper.select:
SELECT * FROM COTDL.TBL_ACCESS_LOG_COLLECT_STATUS
WHERE source_id = #{sourceId}
ORDER BY collect_start DESC LIMIT 1

SELECT * FROM COTDL.TBL_ACCESS_LOG_COLLECT_STATUS
WHERE source_id = #{sourceId}
ORDER BY collect_start DESC LIMIT 50

